import{_ as e,c as a,o,aj as t}from"./chunks/framework.CLcCQpUA.js";const i="/ComicGUISpider/assets/conf_usage_en.DX1xF4hN.png",f=JSON.parse('{"title":"🔨 配置","description":"","frontmatter":{},"headers":[],"relativePath":"locate/en/config/index.md","filePath":"locate/en/config/index.md"}'),r={name:"locate/en/config/index.md"},c=t('<h1 id="🔨-配置" tabindex="-1">🔨 配置 <a class="header-anchor" href="#🔨-配置" aria-label="Permalink to &quot;🔨 配置&quot;">​</a></h1><p><img src="'+i+'" alt="conf"></p><div class="info custom-block"><p class="custom-block-title">config file is <code>conf.yml</code>, generated after initial use</p></div><div class="warning custom-block"><p class="custom-block-title">The input box of multiple lines is in <code>yaml</code> format (except for cookies), and a ⚠️ <code>space</code> ⚠️ is required after the <code>colon</code></p></div><h2 id="config-field-corresponding-yml-field" tabindex="-1">Config Field / Corresponding <code>yml</code> Field <a class="header-anchor" href="#config-field-corresponding-yml-field" aria-label="Permalink to &quot;Config Field / Corresponding `yml` Field&quot;">​</a></h2><h3 id="save-path-sv-path" tabindex="-1">Save Path / <code>sv_path</code> <a class="header-anchor" href="#save-path-sv-path" aria-label="Permalink to &quot;Save Path / `sv_path`&quot;">​</a></h3><p>Download directory<br> The <code>web</code> folder in the directory structure is because the default association with the <a href="https://github.com/jasoneri/redViewer" target="_blank" rel="noreferrer"><code>redViewer</code></a> project is set like this</p><hr><h3 id="loglevel-log-level" tabindex="-1">LogLevel / <code>log_level</code> <a class="header-anchor" href="#loglevel-log-level" aria-label="Permalink to &quot;LogLevel / `log_level`&quot;">​</a></h3><p>After the background runs, there will be a log directory, which is the same level as the GUI, and the GUI will give operation guidance when an error occurs</p><h3 id="concurrnum-concurr-num" tabindex="-1">ConcurrNum / <code>concurr_num</code> <a class="header-anchor" href="#concurrnum-concurr-num" aria-label="Permalink to &quot;ConcurrNum / `concurr_num`&quot;">​</a></h3><p>effect download speed</p><h3 id="dedup-isdeduplicate" tabindex="-1">Dedup / <code>isDeduplicate</code> <a class="header-anchor" href="#dedup-isdeduplicate" aria-label="Permalink to &quot;Dedup / `isDeduplicate`&quot;">​</a></h3><p>「filter icon button」<br> When checked, there will be a style hint in the preview window for downloaded<br> At the same time, the download will automatically filter out the existing records</p><div class="info custom-block github-alert"><p class="custom-block-title">Currently only applicable in 🔞</p><p></p></div><h3 id="adduuid-adduuid" tabindex="-1">AddUuid / <code>addUuid</code> <a class="header-anchor" href="#adduuid-adduuid" aria-label="Permalink to &quot;AddUuid / `addUuid`&quot;">​</a></h3><p>「flag icon button」<br> Add an identifier at the end of the directory when storing, which is used to handle different works with the same name</p><h3 id="darkmode-darktheme" tabindex="-1">DarkMode / <code>darkTheme</code> <a class="header-anchor" href="#darkmode-darktheme" aria-label="Permalink to &quot;DarkMode / `darkTheme`&quot;">​</a></h3><p>「moon icon button」<br> switch mode base on boolean</p><hr><h3 id="proxy-proxies" tabindex="-1">Proxy / <code>proxies</code> <a class="header-anchor" href="#proxy-proxies" aria-label="Permalink to &quot;Proxy / `proxies`&quot;">​</a></h3><p>Proxy</p><div class="info custom-block github-alert"><p class="custom-block-title">It is recommended to configure the proxy here, rather than the global proxy mode, otherwise a lot of proxy traffic will be consumed when accessing the source</p><p></p></div><h3 id="pypisource-pypi-source" tabindex="-1">PypiSource / <code>pypi_source</code> <a class="header-anchor" href="#pypisource-pypi-source" aria-label="Permalink to &quot;PypiSource / `pypi_source`&quot;">​</a></h3><p>If not pypi, choose pypi plz</p><h3 id="uilanguage-lang" tabindex="-1">UiLanguage / <code>lang</code> <a class="header-anchor" href="#uilanguage-lang" aria-label="Permalink to &quot;UiLanguage / `lang`&quot;">​</a></h3><p>Ddefault by system language<br> switch language will take effect after save and reboot</p><hr><h3 id="mapping-custom-map" tabindex="-1">Mapping / <code>custom_map</code> <a class="header-anchor" href="#mapping-custom-map" aria-label="Permalink to &quot;Mapping / `custom_map`&quot;">​</a></h3><p>Search input mapping<br> When the search does not meet the preset, first add the key-value pair here, and after restarting, the corresponding website results will be output when entering the custom key in the search box</p><ol><li>Mapping does not need to care about the domain name, as long as it is used in the current website, as long as it meets <code>can access without mapping</code> and <code>the entered is not an invalid url</code>, the program will automatically replace it with a usable domain name, such as <code>wnacg.com</code> will be automatically replaced with the default domain name under non-proxy mapping</li><li>Note that the custom mapping may exceed the range of the paging rule, and at this time, it can be notified to the developer for expansion</li></ol><h3 id="preset-completer" tabindex="-1">Preset / <code>completer</code> <a class="header-anchor" href="#preset-completer" aria-label="Permalink to &quot;Preset / `completer`&quot;">​</a></h3><p>Custom preset<br> There will be a <code>number corresponding to the website</code> prompt when the mouse hovers over the input box (in fact, it is the number of the choose-box)</p><h3 id="cookies-cookies" tabindex="-1">Cookies / <code>cookies</code> <a class="header-anchor" href="#cookies-cookies" aria-label="Permalink to &quot;Cookies / `cookies`&quot;">​</a></h3><p>It is necessary to use <code>exhentai</code><br><a href="https://raw.githubusercontent.com/jasoneri/imgur/main/CGS/ehentai_get_cookies_new.gif" target="_blank" rel="noreferrer">🎬 Method of acquisition</a><br><a href="https://tool.lu/en_US/curl/" target="_blank" rel="noreferrer">🔗 Tool Website</a> Now support paste curl string to Edit, CGS will inner handle it.</p><hr><h3 id="clipdb-clip-db" tabindex="-1">ClipDb / <code>clip_db</code> <a class="header-anchor" href="#clipdb-clip-db" aria-label="Permalink to &quot;ClipDb / `clip_db`&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">If function of read-clip wanted, Need Clipboard Soft be installed</p><p>win: <a href="https://github.com/sabrogden/Ditto" target="_blank" rel="noreferrer">🌐Ditto</a><br> macOS: <a href="https://github.com/p0deje/Maccy" target="_blank" rel="noreferrer">🌐Maccy</a></p></div><p>When the clipboard reading function unusable, check whether the db exists, and fix it here after obtaining the correct path</p><ol><li>ditto(win): Open options → Database path</li><li>maccy(macOS): <a href="https://github.com/p0deje/Maccy/issues/271" target="_blank" rel="noreferrer">issue search for related information</a></li></ol><h3 id="clipentries-clip-read-num" tabindex="-1">ClipEntries / <code>clip_read_num</code> <a class="header-anchor" href="#clipentries-clip-read-num" aria-label="Permalink to &quot;ClipEntries / `clip_read_num`&quot;">​</a></h3><p>Number of items read from the clipboard software</p><h2 id="other-yml-field" tabindex="-1">Other <code>yml</code> Field <a class="header-anchor" href="#other-yml-field" aria-label="Permalink to &quot;Other `yml` Field&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">The following fields are not displayed in the Config Dialog, set default value unless customize</p></div><h3 id="img-sv-type" tabindex="-1"><code>img_sv_type</code> <a class="header-anchor" href="#img-sv-type" aria-label="Permalink to &quot;`img_sv_type`&quot;">​</a></h3><p>default: <code>jpg</code><br> image file name suffix</p><h3 id="rv-script" tabindex="-1"><code>rv_script</code> <a class="header-anchor" href="#rv-script" aria-label="Permalink to &quot;`rv_script`&quot;">​</a></h3><p>default:<br> bind rV(redViewer) script，use to start etc.</p><h3 id="bg-path" tabindex="-1"><code>bg_path</code> <a class="header-anchor" href="#bg-path" aria-label="Permalink to &quot;`bg_path`&quot;">​</a></h3><p>default:<br> CGS will scan png under by bg_path，choose one to set background.</p>',50),l=[c];function d(n,s,h,p,u,m){return o(),a("div",null,l)}const g=e(r,[["render",d]]);export{f as __pageData,g as default};
